import android.util.Base64
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import java.security.KeyStore

class SessionProvisioner(
    private val tokenStore: SharedPrefsTokenStore,
    private val backendClient: BackendClient
) {

    // Called immediately after a successful username/password login
    suspend fun provision(username: String, password: String): Result<Unit> =
        withContext(Dispatchers.IO) {
            runCatching {
                // 1. Authenticate to backend, receive session token
                val plainToken = backendClient.login(username, password)  // returns String

                // 2. Generate (or regenerate) the Keystore key BEFORE encrypting
                val key = KeystoreHelper.getOrCreateKey()

                // 3. Encrypt immediately — plainToken lives in memory only here
                val (iv, ciphertext) = KeystoreHelper.encrypt(plainToken, key)

                // 4. Persist ciphertext + IV; write active key alias
                tokenStore.writeEncryptedToken(
                    iv         = Base64.encodeToString(iv, Base64.NO_WRAP),
                    ciphertext = Base64.encodeToString(ciphertext, Base64.NO_WRAP),
                    keyAlias   = KeystoreHelper.ACTIVE_KEY_ALIAS
                )
                // plainToken goes out of scope here and is eligible for GC
            }
        }
}

import java.security.KeyStore
import javax.crypto.KeyGenerator
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties

class KeyRotationManager(
    private val biometricAuthManager: BiometricAuthManager,
    private val tokenStore: SharedPrefsTokenStore,
    private val backendClient: BackendClient
) {

    companion object {
        private const val NEXT_KEY_ALIAS = "claude_session_key_next"
    }

    // Rotate in response to a trigger; newTokenViaBackend=true when server forced rotation
    suspend fun rotate(
        currentPlainToken: String,   // already decrypted via biometric in caller
        newTokenViaBackend: Boolean = true
    ): Result<Unit> = withContext(Dispatchers.IO) {
        runCatching {
            // Step 2: Generate K2 with a distinct alias
            val k2 = generateNextKey()

            // Step 3: Obtain a new session token (or re-use the current one if same token)
            val newToken = if (newTokenViaBackend) {
                backendClient.rotateToken(bearerToken = currentPlainToken)  // server issues T2
            } else {
                currentPlainToken   // same token, new key — e.g. scheduled re-encryption
            }

            // Step 4: Encrypt T2 with K2
            val (iv2, ciphertext2) = KeystoreHelper.encrypt(newToken, k2)

            // Step 5: Write C2 + IV2 atomically; do NOT yet update active alias
            tokenStore.writePendingToken(
                iv         = Base64.encodeToString(iv2, Base64.NO_WRAP),
                ciphertext = Base64.encodeToString(ciphertext2, Base64.NO_WRAP),
                pendingAlias = NEXT_KEY_ALIAS
            )

            // Step 6: Commit — update active alias, then delete K1
            tokenStore.commitPendingToken()   // atomically swaps "active" alias
            deleteOldKey(KeystoreHelper.ACTIVE_KEY_ALIAS)

        }.onFailure { e ->
            // Rollback: delete K2 if it was created; C1 + IV1 remain
            safeDeleteKey(NEXT_KEY_ALIAS)
            throw e
        }
    }

    private fun generateNextKey(): javax.crypto.SecretKey {
        safeDeleteKey(NEXT_KEY_ALIAS)   // clean up any previous incomplete rotation
        val gen = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES, "AndroidKeyStore"
        )
        gen.init(
            KeyGenParameterSpec.Builder(
                NEXT_KEY_ALIAS,
                KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                .setKeySize(256)
                .setUserAuthenticationRequired(true)
                .setUserAuthenticationParameters(
                    0, KeyProperties.AUTH_BIOMETRIC_STRONG
                )
                .build()
        )
        return gen.generateKey()
    }

    private fun safeDeleteKey(alias: String) {
        runCatching {
            KeyStore.getInstance("AndroidKeyStore").apply { load(null) }.deleteEntry(alias)
        }
    }

    private fun deleteOldKey(alias: String) {
        KeyStore.getInstance("AndroidKeyStore").apply { load(null) }.deleteEntry(alias)
    }
}

import androidx.work.CoroutineWorker
import androidx.work.ExistingPeriodicWorkPolicy
import androidx.work.PeriodicWorkRequestBuilder
import androidx.work.WorkManager
import androidx.work.WorkerParameters
import java.util.concurrent.TimeUnit

// Schedules the rotation check — call from Application.onCreate()
fun scheduleRotationCheck(context: Context) {
    val request = PeriodicWorkRequestBuilder<RotationCheckWorker>(
        repeatInterval = 30,
        repeatIntervalTimeUnit = TimeUnit.DAYS
    ).build()

    WorkManager.getInstance(context).enqueueUniquePeriodicWork(
        "session_token_rotation",
        ExistingPeriodicWorkPolicy.KEEP,  // don't reset if already scheduled
        request
    )
}

class RotationCheckWorker(
    ctx: Context,
    params: WorkerParameters
) : CoroutineWorker(ctx, params) {

    override suspend fun doWork(): Result {
        val prefs = applicationContext.getSharedPreferences("app_prefs", Context.MODE_PRIVATE)
        val lastRotation = prefs.getLong("last_rotation_epoch_ms", 0L)
        val thirtyDaysMs = 30L * 24 * 60 * 60 * 1000

        if (System.currentTimeMillis() - lastRotation > thirtyDaysMs) {
            // Signal the UI layer that rotation is needed on next foreground
            prefs.edit().putBoolean("rotation_pending", true).apply()
        }
        return Result.success()
    }
}

// Backend returns HTTP 401 with a specific error code
data class ApiError(val code: String, val message: String)

class BackendClient(private val httpClient: OkHttpClient) {

    // Throws RotationRequiredException when server signals stale token
    suspend fun completeChatTurn(
        bearerToken: String,
        userMessage: String
    ): Flow<String> = flow {
        val response = makeRequest(bearerToken, userMessage)
        if (response.code == 401) {
            val error = parseError(response)
            if (error.code == "TOKEN_ROTATION_REQUIRED") {
                throw RotationRequiredException("Server requires token rotation")
            }
            throw AuthenticationException(error.message)
        }
        // stream SSE chunks ...
    }
}

class RotationRequiredException(msg: String) : Exception(msg)

// In ChatViewModel — catch and re-route
private suspend fun streamWithToken(token: String, text: String) {
    try {
        backend.completeChatTurn(token, text).collect { delta -> /* update UI */ }
    } catch (e: RotationRequiredException) {
        _state.update { ChatUiState.RotationRequired }  // triggers biometric + rotation flow
    }
}

fun handleBiometricEnrollmentChange(tokenStore: SharedPrefsTokenStore, onReloginNeeded: () -> Unit) {
    val ks = KeyStore.getInstance("AndroidKeyStore").apply { load(null) }

    // Detect stale keys: try to init a Cipher for each known alias
    listOf(KeystoreHelper.ACTIVE_KEY_ALIAS, "claude_session_key_next").forEach { alias ->
        val key = ks.getKey(alias, null) as? javax.crypto.SecretKey ?: return@forEach
        try {
            val cipher = javax.crypto.Cipher.getInstance("AES/GCM/NoPadding")
            cipher.init(javax.crypto.Cipher.ENCRYPT_MODE, key)   // will throw if invalidated
        } catch (e: android.security.keystore.KeyPermanentlyInvalidatedException) {
            ks.deleteEntry(alias)
        }
    }

    // If active key is gone, all stored ciphertext is unrecoverable
    if (!ks.containsAlias(KeystoreHelper.ACTIVE_KEY_ALIAS)) {
        tokenStore.clearAll()
        onReloginNeeded()   // send user through login flow to provision a new token
    }
}
